// ==================== ADMIN LOGIN ====================
function AdminLogin({ onLogin }) {
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');
  const [err, setErr] = useState('');

  const handleLogin = async (e) => {
    e.preventDefault();
    const res = await fetch(`${API}/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password: pass }),
    });
    const data = await res.json();
    if (data.success) onLogin(data.token);
    else setErr('Invalid credentials');
  };

  return (
    <div className="admin-login">
      <div className="login-card">
        <h2>Admin Login</h2>
        <form onSubmit={handleLogin}>
          <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={pass} onChange={e => setPass(e.target.value)} required />
          {err && <p className="error">{err}</p>}
          <button type="submit">Login</button>
        </form>
      </div>
    </div>
  );
}

// ==================== ADMIN PANEL ====================
function AdminPanel({ token, content, onUpdate, onLogout }) {
  const [section, setSection] = useState('hero');
  const [editData, setEditData] = useState(null);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    if (content) setEditData(JSON.parse(JSON.stringify(content[section])));
  }, [section, content]);

  const handleSave = async () => {
    await updateSection(section, editData, token);
    onUpdate(section, editData);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const sections = ['hero', 'aboutProject', 'floorPlans', 'amenities', 'aboutDeveloper', 'constructionUpdates', 'faqs'];

  const renderEditor = (obj, path = '') => {
    if (!obj) return null;
    return Object.entries(obj).map(([key, val]) => {
      const fullPath = path ? `${path}.${key}` : key;
      if (typeof val === 'string') {
        return (
          <div key={fullPath} className="edit-field">
            <label>{fullPath}</label>
            <textarea
              value={val}
              rows={val.length > 100 ? 4 : 2}
              onChange={e => {
                const keys = fullPath.split('.');
                const newData = JSON.parse(JSON.stringify(editData));
                let ref = newData;
                keys.slice(0, -1).forEach(k => ref = ref[k]);
                ref[keys[keys.length - 1]] = e.target.value;
                setEditData(newData);
              }}
            />
          </div>
        );
      }
      if (Array.isArray(val)) {
        return (
          <div key={fullPath} className="edit-array">
            <label className="array-label">{fullPath} (array)</label>
            {val.map((item, i) =>
              typeof item === 'object'
                ? <div key={i} className="array-item"><strong>Item {i + 1}</strong>{renderEditor(item, `${fullPath}.${i}`)}</div>
                : <div key={i} className="edit-field">
                    <label>{fullPath}[{i}]</label>
                    <input value={item} onChange={e => {
                      const keys = fullPath.split('.');
                      const newData = JSON.parse(JSON.stringify(editData));
                      let ref = newData;
                      keys.slice(0, -1).forEach(k => ref = Array.isArray(ref) ? ref[parseInt(k)] : ref[k]);
                      ref[keys[keys.length-1]][i] = e.target.value;
                      setEditData(newData);
                    }} />
                  </div>
            )}
          </div>
        );
      }
      if (typeof val === 'object') return <div key={fullPath} className="edit-nested"><label className="nested-label">{fullPath}</label>{renderEditor(val, fullPath)}</div>;
      return null;
    });
  };

  return (
    <div className="admin-panel">
      <div className="admin-sidebar">
        <h3>🏡 Admin Panel</h3>
        {sections.map(s => (
          <button key={s} className={section === s ? 'active' : ''} onClick={() => setSection(s)}>
            {s.charAt(0).toUpperCase() + s.slice(1).replace(/([A-Z])/g, ' $1')}
          </button>
        ))}
        <button className="logout-btn" onClick={onLogout}>Logout</button>
      </div>
      <div className="admin-content">
        <div className="admin-header">
          <h2>Edit: {section}</h2>
          <div>
            {saved && <span className="saved-msg">✅ Saved!</span>}
            <button className="btn-save" onClick={handleSave}>Save Changes</button>
            <a href="/" target="_blank" className="btn-preview">Preview Site ↗</a>
          </div>
        </div>
        <div className="edit-form">{editData && renderEditor(editData)}</div>
      </div>
    </div>
  );
}

// ==================== MAIN APP ====================
export default function App() {
  const [content, setContent] = useState(null);
  const [adminToken, setAdminToken] = useState(localStorage.getItem('adminToken'));
  const [page, setPage] = useState(window.location.pathname === '/admin' ? 'admin' : 'site');

  useEffect(() => {
    fetchContent().then(setContent);
  }, []);

  const handleLogin = (token) => {
    localStorage.setItem('adminToken', token);
    setAdminToken(token);
  };

  const handleLogout = () => {
    localStorage.removeItem('adminToken');
    setAdminToken(null);
  };

  const handleUpdate = (section, data) => {
    setContent(prev => ({ ...prev, [section]: data }));
  };

  if (!content) return <div className="loading"><div className="spinner"></div><p>Loading...</p></div>;

  // Admin route
  if (page === 'admin') {
    if (!adminToken) return <AdminLogin onLogin={handleLogin} />;
    return <AdminPanel token={adminToken} content={content} onUpdate={handleUpdate} onLogout={handleLogout} />;
  }

  return (
    <div className="app">
      <div className="admin-bar">
        <span>Real Estate Website</span>
        <button onClick={() => setPage('admin')}>Admin Panel →</button>
      </div>
      <Navbar />
      <HeroSection data={content.hero} />
      <AboutProject data={content.aboutProject} />
      <FloorPlans data={content.floorPlans} />
      <Amenities data={content.amenities} />
      <MoreBuildings title={content.moreBuildingsTitle} />
      <AboutDeveloper data={content.aboutDeveloper} />
      <ConstructionUpdates data={content.constructionUpdates} />
      <FAQ data={content.faqs} />
      <footer className="footer" id="contact">
        <p>© 2024 Vighnaharta Infinity. All Rights Reserved.</p>
      </footer>
    </div>
  );
}
